{
  "title": "Introduction to Python for Game Development",
  "description": "This course is designed for beginners who want to learn Python with a focus on game development. Through four comprehensive modules, learners will gain foundational Python skills and apply them to create simple games.",
  "modules": [
    {
      "id": "module1",
      "title": "Getting Started with Python",
      "description": "Learn the basics of Python programming, including syntax, data types, and control structures. Set up your development environment and write your first Python script."
    },
    {
      "id": "module2",
      "title": "Understanding Game Development Concepts",
      "description": "Explore fundamental concepts in game development, including game loops, events, and user input. Understand how these concepts apply to Python programming."
    },
    {
      "id": "module3",
      "title": "Introduction to Pygame",
      "description": "Get introduced to Pygame, a popular library for game development in Python. Learn how to install Pygame and create basic 2D games using graphics and sound."
    },
    {
      "id": "module4",
      "title": "Building Your First Game",
      "description": "Apply your knowledge by developing a simple game project. Implement game mechanics, user interaction, and polish your game for presentation."
    }
  ]
}
